// ───── TYPE DEFINITIONS ─────

export type LoopType = 'research' | 'review' | 'context';

export type ResearchNodeKind = 'QUESTION' | 'FINDING' | 'CLAIM' | 'SOURCE';

export type ReviewNodeKind =
  | 'DIMENSION'
  | 'FILE'
  | 'FINDING'
  | 'EVIDENCE'
  | 'REMEDIATION'
  | 'BUG_CLASS'
  | 'INVARIANT'
  | 'PRODUCER'
  | 'CONSUMER'
  | 'TEST';

export type ContextNodeKind =
  | 'SLICE'
  | 'FILE'
  | 'SYMBOL'
  | 'PATTERN'
  | 'REUSE_CANDIDATE'
  | 'DEPENDENCY'
  | 'CONSTRAINT'
  | 'GAP';

export type NodeKind = ResearchNodeKind | ReviewNodeKind | ContextNodeKind;

export type ResearchRelation =
  | 'ANSWERS'
  | 'SUPPORTS'
  | 'CONTRADICTS'
  | 'SUPERSEDES'
  | 'DERIVED_FROM'
  | 'COVERS'
  | 'CITES';

export type ReviewRelation =
  | 'COVERS'
  | 'EVIDENCE_FOR'
  | 'CONTRADICTS'
  | 'RESOLVES'
  | 'CONFIRMS'
  | 'ESCALATES'
  | 'IN_DIMENSION'
  | 'IN_FILE';

export type ContextRelation =
  | 'CONTAINS'
  | 'REFERENCES'
  | 'IMPORTS'
  | 'DEPENDS_ON'
  | 'IMPLEMENTS'
  | 'EXPOSES'
  | 'REUSES'
  | 'CONSTRAINS'
  | 'COVERED_BY'
  | 'CONFIRMS'
  | 'CONTRADICTS';

export type Relation = ResearchRelation | ReviewRelation | ContextRelation;

export interface CoverageNode {
  id: string;
  specFolder: string;
  loopType: LoopType;
  sessionId: string;
  kind: NodeKind;
  name: string;
  contentHash?: string;
  iteration?: number;
  metadata?: Record<string, unknown>;
  createdAt?: string;
  updatedAt?: string;
}

export interface CoverageEdge {
  id: string;
  specFolder: string;
  loopType: LoopType;
  sessionId: string;
  sourceId: string;
  targetId: string;
  relation: Relation;
  weight: number;
  metadata?: Record<string, unknown>;
  createdAt?: string;
}

export interface CoverageSnapshot {
  id?: number;
  specFolder: string;
  loopType: LoopType;
  sessionId: string;
  iteration: number;
  metrics: Record<string, unknown>;
  nodeCount: number;
  edgeCount: number;
  createdAt?: string;
}

export interface Namespace {
  specFolder: string;
  loopType: LoopType;
  sessionId?: string;
}

// ───── CONSTANTS ─────

export const SCHEMA_VERSION = 3;

const DB_FILENAME = 'deep-loop-graph.sqlite';
export const COVERAGE_GRAPH_DATABASE_DIR = join(
  dirname(fileURLToPath(import.meta.url)),
  '..',
  '..',
  'database',
);

const MIN_WEIGHT = 0.0;
const MAX_WEIGHT = 2.0;

export const RESEARCH_WEIGHTS: Record<ResearchRelation, number> = {
  ANSWERS: 1.3,
  SUPPORTS: 1.0,
  CONTRADICTS: 0.8,
  SUPERSEDES: 1.5,
  DERIVED_FROM: 1.0,
  COVERS: 1.1,
