};

export const REVIEW_WEIGHTS: Record<ReviewRelation, number> = {
  COVERS: 1.3,
  EVIDENCE_FOR: 1.0,
  CONTRADICTS: 0.8,
  RESOLVES: 1.5,
  CONFIRMS: 1.0,
  ESCALATES: 1.2,
  IN_DIMENSION: 1.0,
  IN_FILE: 1.0,
};

// Context relation weights: REUSES is highest — surfacing existing code to extend
// is the primary value of context gathering (the repo "reuse, avoid new code" principle).
export const CONTEXT_WEIGHTS: Record<ContextRelation, number> = {
  CONTAINS: 1.0,
  REFERENCES: 1.0,
  IMPORTS: 1.2,
  DEPENDS_ON: 1.2,
  IMPLEMENTS: 1.4,
